import React, { useState, useEffect } from 'react';

export default function InsightSearch() {
  const [query, setQuery] = useState('');
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const [insightOptions, setInsightOptions] = useState([]);

  useEffect(() => {
    // Fetch available insights for dropdown
    fetch('/api/insights')
      .then(res => res.json())
      .then(data => {
        setInsightOptions(data.map(i => i.insightName));
      })
      .catch(err => console.error('Failed to load insight list:', err));
  }, []);

  const searchInsight = async () => {
    try {
      const res = await fetch(`/api/insight/search?q=${encodeURIComponent(query)}`);
      if (!res.ok) throw new Error("Insight not found or server error");
      const data = await res.json();
      setResult(data);
      setError(null);
    } catch (err) {
      setResult(null);
      setError(err.message);
    }
  };

  return (
    <div className="max-w-6xl mx-auto p-6 space-y-6">
      <h1 className="text-2xl font-bold">Insight Search UI</h1>

      {/* Search bar with dropdown */}
      <div className="flex gap-4">
        <select
          className="border border-gray-300 rounded px-3 py-2 w-full"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
        >
          <option value="">-- Select an Insight --</option>
          {insightOptions.map((insight, idx) => (
            <option key={idx} value={insight}>{insight}</option>
          ))}
        </select>

        <button
          onClick={searchInsight}
          className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
        >
          filter
        </button>
      </div>

      {/* Error message */}
      {error && <p className="text-red-500">❌ {error}</p>}

      {/* Results */}
      {result && (
        <div className="border rounded shadow p-6 space-y-6 bg-white">
          <div>
            <h2 className="text-xl font-semibold">{result.insightName}</h2>
            <p><strong>Calculation:</strong> {result.calculation}</p>
            <p><strong>Used in Products:</strong> {result.productsUsedIn.join(', ')}</p>
          </div>

          {/* Unified Data Points Table */}
          {result.dataPoints?.length > 0 && (
            <div>
              <h3 className="text-lg font-semibold mt-4">Data Point Mappings</h3>
              <div className="overflow-x-auto mt-2">
                <table className="w-full text-sm border border-gray-300">
                  <thead>
                    <tr className="bg-gray-100 text-left">
                      <th className="border px-3 py-2">Data Point</th>
                      <th className="border px-3 py-2">Source</th>
                      <th className="border px-3 py-2">System</th>
                      <th className="border px-3 py-2">Table</th>
                      <th className="border px-3 py-2">Field</th>
                      <th className="border px-3 py-2">Data Type</th>
                    </tr>
                  </thead>
                  <tbody>
                    {result.dataPoints.map((dp, index) => (
                      Array.isArray(dp.sourceMapping) && dp.sourceMapping.length > 0 ? (
                        dp.sourceMapping.map((m, i) => (
                          <tr key={`${index}-${i}`} className="even:bg-gray-50">
                            <td className="border px-3 py-2">{dp.name}</td>
                            <td className="border px-3 py-2">{m.sourceName}</td>
                            <td className="border px-3 py-2">{m.sourceSystem}</td>
                            <td className="border px-3 py-2">{m.table}</td>
                            <td className="border px-3 py-2">{m.field}</td>
                            <td className="border px-3 py-2">{m.dataType}</td>
                          </tr>
                        ))
                      ) : (
                        <tr key={index} className="bg-red-50">
                          <td className="border px-3 py-2">{dp.name}</td>
                          <td className="border px-3 py-2 text-red-500" colSpan={5}>
                            No source mappings found
                          </td>
                        </tr>
                      )
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
